import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"墨绿披风","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/1.D级/墨绿披风.md","filePath":"4.资源分区/7.物品与装备/4.奇物/1.D级/墨绿披风.md"}'),d={name:"4.资源分区/7.物品与装备/4.奇物/1.D级/墨绿披风.md"};function l(_,a,b,i,p,c){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"墨绿披风",tabindex:"-1"},[s("墨绿披风 "),e("a",{class:"header-anchor",href:"#墨绿披风","aria-label":'Permalink to "墨绿披风"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新秩序006")])])],-1),o('<h1 id="墨绿披风-1" tabindex="-1">墨绿披风 <a class="header-anchor" href="#墨绿披风-1" aria-label="Permalink to &quot;墨绿披风&quot;">​</a></h1><p>墨绿披风<br> D+500<br> 魔幻本质<br> 占据斗篷位<br> 一张织着绿白相间花纹的披风，披上后会无风自动，适合凸现出穿戴者的飒爽英姿，耐脏美观，它会占据衣物位置，这张披风是一位医师为她的爱人所编织的披风，这张披风初始没有花纹。<br>   每当披风的拥有者穿戴披风经过一场影片，这张披风便会出现两段花纹。<br>  <br> 每当披风出现一段花纹时，拥有者便可以从下列选项中依次获得一项好处；若所有选项都被选择后，再从第一项开始依次获得一项好处。<br> ●只有拥有者在使用转轮类手枪时才能享受此效果，提升使用武器的1级连射等级。连射等级到达最高等级后的每次选择转化为1点武器高速。<br> ●提升1级器用-轻载具驾驶专业，若该专业等级已等同于当前对应技能等级，则改为永久在进行驾驶轻载具检定时额外获得1点表现加值。<br> ●若拥有者此时拥有某种载具，则令那个载具永久增加5点移动速度，这些移动速度只能增加给一个载具，拥有者可以在空间中将这些额外的移动速度转移给他拥有的其他任一种载具；若否，则改为永久为拥有者提供2点先攻。<br> ●拥有者永久获得1点偏斜防御，若其拥有的偏斜防御数值大于拥有者武器上的高速，则改为永久获得1点闪避防御。</p><p>拥有者可以再付D+500，以获得另一种织出花纹的方式：<br> 每购买两个D级及以上射击相关资源*便会出现一段花纹。<br> （射击相关资源：指技艺-射击类内的强化资源，与资源描述中具有【远程】、【射程】、【瞄准】其中之一的强化。）</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',5)])])}const m=r(d,[["render",l]]);export{f as __pageData,m as default};
